            <p className="text-white text-[10px] font-black uppercase tracking-widest mb-2 opacity-80">Toplam İnşaat Alanı</p>
            <p className="text-4xl font-black text-white tracking-tighter">
              {(results.normalKatBrut * results.toplamKat + results.zeminBrut).toFixed(0)} 
