                  <i className="fa-solid fa-compass-drafting text-5xl text-blue-600/50"></i>
                </div>
                <h3 className="text-3xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-tighter">Fizibiliteye Başlayın</h3>
                <p className="text-slate-400 mt-4 text-base max-w-md mx-auto font-medium leading-relaxed">Arsa verilerini girin; TAKS/KAKS, maliyet, malzeme ve AI analizini saniyeler içinde alın.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

