import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ArsaBilgileri, HesapSonuclari } from '../types';

interface AIAdvisorProps {
  data: ArsaBilgileri;
  results: HesapSonuclari;
}

const AIAdvisor: React.FC<AIAdvisorProps> = ({ data, results }) => {
  const [loading, setLoading] = useState(false);
  const [advice, setAdvice] = useState<string>("");

  const getAIAdvice = async () => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        Sen profesyonel bir inşaat mühendisi ve müteahhitlik danışmanısın. 
        Arsa Konumu: ${data.il}/${data.ilce}
        Toplam İnşaat Alanı: ${results.toplamInsaatAlani} m2
        Toplam Maliyet: ${results.toplamMaliyet} TL
        Hedef Satış Geliri: ${results.toplamGelir} TL (Bölgedeki Sahibinden/Hürriyet Emlak fiyatları baz alındı: ${data.birimSatisFiyati} TL/m2)
        Net Kar: ${results.toplamKar} TL
        ROI (Yatırım Dönüşü): %${((results.toplamKar / results.toplamMaliyet) * 100).toFixed(1)}

        Lütfen 3 maddede bu projenin ticari ve teknik risklerini/fırsatlarını özetle. 
        Bölgedeki emlak piyasasına (Sahibinden vb. verilerle uyum) ve maliyet artışlarına dikkat çek. 
        Kısa, profesyonel ve vurucu bir dil kullan.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      setAdvice(response.text || "Finansal analiz oluşturulamadı.");
    } catch (error) {
      setAdvice("AI bağlantısı kurulamadı. Lütfen API anahtarını kontrol edin.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    getAIAdvice();
  }, [data]);

  return (
    <div className="bg-slate-900 text-white p-8 rounded-[2.5rem] shadow-2xl border border-slate-700 relative overflow-hidden group">
      <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
        <i className="fa-solid fa-hand-holding-dollar text-7xl text-emerald-500"></i>
      </div>

      <div className="relative z-10">
        <h4 className="text-xs font-black uppercase tracking-[0.3em] text-emerald-400 mb-4 flex items-center gap-2">
          <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
          AI Finansal Fizibilite Raporu
        </h4>

        {loading ? (
          <div className="space-y-3">
            <div className="h-3 bg-slate-800 rounded-full w-full animate-pulse"></div>
            <div className="h-3 bg-slate-800 rounded-full w-3/4 animate-pulse"></div>
            <div className="h-3 bg-slate-800 rounded-full w-1/2 animate-pulse"></div>
          </div>
        ) : (
          <div className="text-sm font-medium leading-relaxed text-slate-300 whitespace-pre-line italic">
            "{advice}"
          </div>
        )}
      </div>
    </div>
  );
};

export default AIAdvisor;
